/**
 * File-Level Conflict Detector
 * Sprint 6.2-6.3: Detects conflicts in generated files using SHA-256 hashing
 */

const crypto = require('crypto');
const fs = require('fs').promises;
const path = require('path');
const EventEmitter = require('events');

/**
 * Conflict detection result types
 */
const ConflictType = {
  NONE: 'none',
  MODIFIED_LOCALLY: 'modified_locally',
  STALE_GENERATION: 'stale_generation',
  BOTH_MODIFIED: 'both_modified',
  NEW_FILE: 'new_file',
  DELETED_LOCALLY: 'deleted_locally'
};

/**
 * File-level conflict detector with hash registry
 */
class FileConflictDetector extends EventEmitter {
  constructor(options = {}) {
    super();
    this.hashRegistryPath = options.hashRegistryPath || '.design/hash-registry.json';
    this.hashRegistry = new Map();
    this.initialized = false;
  }

  /**
   * Initialize the detector and load existing hash registry
   */
  async initialize(projectPath) {
    this.projectPath = projectPath;
    await this.loadHashRegistry();
    this.initialized = true;
    this.emit('initialized', { projectPath });
    return this;
  }

  /**
   * Compute SHA-256 hash of content
   */
  computeHash(content) {
    return crypto.createHash('sha256').update(content, 'utf8').digest('hex');
  }

  /**
   * Load hash registry from disk
   */
  async loadHashRegistry() {
    const registryPath = path.join(this.projectPath, this.hashRegistryPath);
    try {
      const content = await fs.readFile(registryPath, 'utf8');
      const data = JSON.parse(content);
      this.hashRegistry = new Map(Object.entries(data.files || {}));
      this.emit('registry:loaded', { count: this.hashRegistry.size });
    } catch (error) {
      // Registry doesn't exist yet, start with empty
      this.hashRegistry = new Map();
      this.emit('registry:created', { projectPath: this.projectPath });
    }
  }

  /**
   * Save hash registry to disk
   */
  async saveHashRegistry() {
    const registryPath = path.join(this.projectPath, this.hashRegistryPath);
    const dir = path.dirname(registryPath);

    // Ensure directory exists
    await fs.mkdir(dir, { recursive: true });

    const data = {
      version: '1.0.0',
      updatedAt: new Date().toISOString(),
      files: Object.fromEntries(this.hashRegistry)
    };

    await fs.writeFile(registryPath, JSON.stringify(data, null, 2), 'utf8');
    this.emit('registry:saved', { count: this.hashRegistry.size });
  }

  /**
   * Store hash for a generated file
   */
  async storeHash(filePath, generatedContent, metadata = {}) {
    const relativePath = this.getRelativePath(filePath);
    const hash = this.computeHash(generatedContent);

    this.hashRegistry.set(relativePath, {
      hash,
      generatedAt: new Date().toISOString(),
      figmaNodeId: metadata.figmaNodeId || null,
      framework: metadata.framework || null,
      componentName: metadata.componentName || null
    });

    await this.saveHashRegistry();
    this.emit('hash:stored', { filePath: relativePath, hash });

    return hash;
  }

  /**
   * Get stored hash for a file
   */
  getStoredHash(filePath) {
    const relativePath = this.getRelativePath(filePath);
    return this.hashRegistry.get(relativePath);
  }

  /**
   * Remove hash from registry
   */
  async removeHash(filePath) {
    const relativePath = this.getRelativePath(filePath);
    const existed = this.hashRegistry.delete(relativePath);

    if (existed) {
      await this.saveHashRegistry();
      this.emit('hash:removed', { filePath: relativePath });
    }

    return existed;
  }

  /**
   * Detect conflict for a file
   */
  async detectConflict(filePath, newGeneratedContent) {
    const relativePath = this.getRelativePath(filePath);
    const absolutePath = path.join(this.projectPath, relativePath);

    // Get stored hash info
    const storedInfo = this.hashRegistry.get(relativePath);

    // Check if file exists on disk
    let currentContent = null;
    let fileExists = false;

    try {
      currentContent = await fs.readFile(absolutePath, 'utf8');
      fileExists = true;
    } catch (error) {
      if (error.code !== 'ENOENT') {
        throw error;
      }
    }

    // Compute hashes
    const newHash = this.computeHash(newGeneratedContent);
    const currentHash = currentContent ? this.computeHash(currentContent) : null;
    const storedHash = storedInfo?.hash || null;

    // Determine conflict type
    let conflictType = ConflictType.NONE;
    let details = {};

    if (!storedHash && !fileExists) {
      // New file, no conflict
      conflictType = ConflictType.NEW_FILE;
      details = { message: 'New file will be created' };
    } else if (!storedHash && fileExists) {
      // File exists but wasn't generated by us - potential conflict
      conflictType = ConflictType.MODIFIED_LOCALLY;
      details = {
        message: 'File exists but was not generated by DesignBridge',
        currentHash
      };
    } else if (storedHash && !fileExists) {
      // File was generated but deleted locally
      conflictType = ConflictType.DELETED_LOCALLY;
      details = {
        message: 'File was previously generated but has been deleted locally',
        storedHash
      };
    } else if (storedHash === currentHash) {
      // File unchanged since last generation
      if (newHash === storedHash) {
        // No changes in new generation either
        conflictType = ConflictType.NONE;
        details = { message: 'No changes detected' };
      } else {
        // New generation has changes, safe to update
        conflictType = ConflictType.NONE;
        details = { message: 'File can be safely updated' };
      }
    } else if (storedHash !== currentHash) {
      // File modified locally since last generation
      if (newHash === storedHash) {
        // New generation same as old, only local changes
        conflictType = ConflictType.MODIFIED_LOCALLY;
        details = {
          message: 'File has been modified locally since last generation',
          storedHash,
          currentHash
        };
      } else {
        // Both local changes and new generation changes
        conflictType = ConflictType.BOTH_MODIFIED;
        details = {
          message: 'File modified both locally and in Figma',
          storedHash,
          currentHash,
          newHash
        };
      }
    }

    const result = {
      filePath: relativePath,
      conflictType,
      hasConflict: conflictType !== ConflictType.NONE && conflictType !== ConflictType.NEW_FILE,
      storedHash,
      currentHash,
      newHash,
      storedInfo,
      ...details
    };

    this.emit('conflict:detected', result);
    return result;
  }

  /**
   * Detect conflicts for multiple files
   */
  async detectConflicts(files) {
    const results = [];

    for (const file of files) {
      const result = await this.detectConflict(file.path, file.content);
      results.push(result);
    }

    const conflicts = results.filter(r => r.hasConflict);

    this.emit('conflicts:detected', {
      total: results.length,
      conflicts: conflicts.length,
      results
    });

    return {
      total: results.length,
      conflicts: conflicts.length,
      hasConflicts: conflicts.length > 0,
      results
    };
  }

  /**
   * Update hash after successful file write
   */
  async updateHashAfterWrite(filePath, content, metadata = {}) {
    return this.storeHash(filePath, content, metadata);
  }

  /**
   * Get all tracked files
   */
  getTrackedFiles() {
    return Array.from(this.hashRegistry.keys());
  }

  /**
   * Get registry statistics
   */
  getStats() {
    return {
      trackedFiles: this.hashRegistry.size,
      initialized: this.initialized,
      projectPath: this.projectPath
    };
  }

  /**
   * Clear hash registry (for testing or reset)
   */
  async clearRegistry() {
    this.hashRegistry.clear();
    await this.saveHashRegistry();
    this.emit('registry:cleared');
  }

  /**
   * Get relative path from absolute
   */
  getRelativePath(filePath) {
    if (path.isAbsolute(filePath)) {
      return path.relative(this.projectPath, filePath);
    }
    return filePath;
  }

  /**
   * Bulk store hashes (after batch generation)
   */
  async bulkStoreHashes(files) {
    for (const file of files) {
      const relativePath = this.getRelativePath(file.path);
      const hash = this.computeHash(file.content);

      this.hashRegistry.set(relativePath, {
        hash,
        generatedAt: new Date().toISOString(),
        figmaNodeId: file.metadata?.figmaNodeId || null,
        framework: file.metadata?.framework || null,
        componentName: file.metadata?.componentName || null
      });
    }

    await this.saveHashRegistry();
    this.emit('hashes:bulk-stored', { count: files.length });

    return files.length;
  }
}

/**
 * Factory function
 */
function createFileConflictDetector(options = {}) {
  return new FileConflictDetector(options);
}

module.exports = FileConflictDetector;
module.exports.FileConflictDetector = FileConflictDetector;
module.exports.createFileConflictDetector = createFileConflictDetector;
module.exports.ConflictType = ConflictType;
